document.addEventListener("DOMContentLoaded",function(){document.querySelector(".hero-btn").addEventListener("click",()=>{document.querySelector("#concerts").scrollIntoView()});const e=document.getElementById("contact-form");e&&e.addEventListener("submit",function(t){t.preventDefault();const o=e.elements.name.value.trim(),n=e.elements.email.value.trim(),c=e.elements.message.value.trim();let s=!0,l="";if(o.length<2&&(s=!1,l+="Введіть коректне ім'я (мінімум 2 символи).\n"),/^\S+@\S+\.\S+$/.test(n)||(s=!1,l+="Введіть коректний email.\n"),c.length<5&&(s=!1,l+="Введіть повідомлення (мінімум 5 символів)."),s){const t=new URLSearchParams({name:o,email:n,message:c});fetch("/contact-form?"+t.toString(),{method:"GET"}).then(()=>{document.querySelector(".form-success").style.display="block",setTimeout(()=>{document.querySelector(".form-success").style.display="none",e.reset()},3e3)})}else alert(l)})});const modal=document.getElementById("modal"),openBtns=document.querySelectorAll(".btn-table"),closeBtn=document.querySelector(".modal-close"),overlay=document.querySelector(".modal-overlay"),popupCity=document.querySelector("#popupCity"),orderForm=document.querySelector(".order-form");function openModal(){modal.classList.add("active"),document.body.classList.add("modal-open")}function closeModal(){modal.classList.remove("active"),document.body.classList.remove("modal-open")}orderForm.addEventListener("submit",e=>{e.preventDefault(),document.querySelector(".form-success2").style.display="block",setTimeout(()=>{document.querySelector(".form-success2").style.display="none",orderForm.reset(),closeModal()},3e3)}),openBtns.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset.city;popupCity.textContent=t,modal.classList.add("active"),document.body.classList.add("modal-open")})}),closeBtn.addEventListener("click",closeModal),overlay.addEventListener("click",closeModal),document.addEventListener("keydown",e=>{"Escape"===e.key&&modal.classList.contains("active")&&closeModal()});